        value = withContext(Dispatchers.IO) {
            mapOf(
                "acc" to PermissionManager.hasAccessibility(ctx),
                "usage" to PermissionManager.hasUsageStats(ctx),
                "files" to PermissionManager.hasAllFilesAccess(ctx),
