// --- PREMIUM SLATE THEME ---
val BgSlate = Color(0xFF0F172A)
val CardSlate = Color(0xFF1E293B)
val AccentBlue = Color(0xFF3B82F6)
val AccentGreen = Color(0xFF10B981)
val AccentPurple = Color(0xFFA855F7)
